const input = $input.first().json;
const data = input.body || {};
const { id, nombre, email, whatsapp, nivel, estado, categoria, horario_clase, origen, intencion, estado_pago, fecha_pago_ultimo, notas } = data;

if (!id) {
  throw new Error('ID es requerido');
}

const updates = [];
if (nombre !== undefined) updates.push(`nombre = '${nombre.replace(/'/g, "''")}' `);
if (email !== undefined) updates.push(`email = ${email ? `'${email.replace(/'/g, "''")}' ` : 'NULL'}`);
if (whatsapp !== undefined) updates.push(`whatsapp = ${whatsapp ? `'${whatsapp.replace(/'/g, "''")}' ` : 'NULL'}`);
if (nivel !== undefined) updates.push(`nivel = ${nivel ? `'${nivel}' ` : 'NULL'}`);
if (estado !== undefined) updates.push(`estado = '${estado}' `);
if (categoria !== undefined) updates.push(`categoria = '${categoria}' `);
if (horario_clase !== undefined) updates.push(`horario_clase = ${horario_clase ? `'${horario_clase.replace(/'/g, "''")}' ` : 'NULL'}`);
if (origen !== undefined) updates.push(`origen = ${origen ? `'${origen.replace(/'/g, "''")}' ` : 'NULL'}`);
if (intencion !== undefined) updates.push(`intencion = ${intencion ? `'${intencion.replace(/'/g, "''")}' ` : 'NULL'}`);
if (estado_pago !== undefined) updates.push(`estado_pago = ${estado_pago ? `'${estado_pago}' ` : 'NULL'}`);
if (fecha_pago_ultimo !== undefined) updates.push(`fecha_pago_ultimo = ${fecha_pago_ultimo ? `'${fecha_pago_ultimo}' ` : 'NULL'}`);
if (notas !== undefined) updates.push(`notas = ${notas ? `'${notas.replace(/'/g, "''")}' ` : 'NULL'}`);

if (updates.length === 0) {
  throw new Error('No hay campos para actualizar');
}

updates.push('updated_at = NOW()');

const query = `UPDATE alumnos SET ${updates.join(', ')} WHERE id = ${parseInt(id)} RETURNING id, nombre, email, whatsapp, nivel, estado, categoria, horario_clase, origen, intencion, estado_pago, fecha_pago_ultimo, notas, activo, created_at, updated_at;`;

return [{
  json: {
    query
  }
}];

const resultado = $('update_alumno').all();

if (resultado.length === 0) {
  return [{
    json: {
      success: false,
      message: 'Alumno no encontrado',
      alumno: null
    }
  }];
}

const alumno = resultado[0].json;

return [{
  json: {
    success: true,
    message: 'Alumno actualizado correctamente',
    alumno: alumno
  }
}];
